changeSet.sql:
-- Malaria RDT Lot INSERT INTO clinlims.inventory_lot ( id, fhir_uuid, inventory_item_id, lot_number, initial_quantity, current_quantity, receipt_date, expiration_date, qc_status, status ) SELECT nextval('clinlims.inventory_lot_seq'), uuid_generate_v4(), ii.id, 'MNTD-RDT-2025-001', 500.0, 485.0, CURRENT_TIMESTAMP - INTERVAL '15 days', CURRENT_TIMESTAMP + INTERVAL '18 months', 'PASSED', 'IN_USE' FROM clinlims.inventory_item ii WHERE ii.name = 'Malaria RDT (Pf/Pv)' AND ii.project_name = 'Malaria and Neglected Tropical Disease (MNTD) Laboratory' AND NOT EXISTS ( SELECT 1 FROM clinlims.inventory_lot il2 WHERE il2.lot_number = 'MNTD-RDT-2025-001' );
-- Dengue Test Lot INSERT INTO clinlims.inventory_lot ( id, fhir_uuid, inventory_item_id, lot_number, initial_quantity, current_quantity, receipt_date, expiration_date, qc_status, status ) SELECT nextval('clinlims.inventory_lot_seq'), uuid_generate_v4(), ii.id, 'MNTD-DNG-2025-002', 200.0, 200.0, CURRENT_TIMESTAMP - INTERVAL '5 days', CURRENT_TIMESTAMP + INTERVAL '12 months', 'PENDING', 'ACTIVE' FROM clinlims.inventory_item ii WHERE ii.name = 'Dengue NS1 Antigen Test' AND ii.project_name = 'Malaria and Neglected Tropical Disease (MNTD) Laboratory' AND NOT EXISTS ( SELECT 1 FROM clinlims.inventory_lot il2 WHERE il2.lot_number = 'MNTD-DNG-2025-002' );
-- HIV ELISA Lot INSERT INTO clinlims.inventory_lot ( id, fhir_uuid, inventory_item_id, lot_number, initial_quantity, current_quantity, receipt_date, expiration_date, qc_status, status ) SELECT nextval('clinlims.inventory_lot_seq'), uuid_generate_v4(), ii.id, 'IMMUNO-HIV-2025-003', 96.0, 72.0, CURRENT_TIMESTAMP - INTERVAL '30 days', CURRENT_TIMESTAMP + INTERVAL '6 months', 'PASSED', 'IN_USE' FROM clinlims.inventory_item ii WHERE ii.name = 'HIV ELISA Test Kit' AND ii.project_name = 'Immunology Laboratory' AND NOT EXISTS ( SELECT 1 FROM clinlims.inventory_lot il2 WHERE il2.lot_number = 'IMMUNO-HIV-2025-003' );
-- CD4 Count Kit Lot INSERT INTO clinlims.inventory_lot ( id, fhir_uuid, inventory_item_id, lot_number, initial_quantity, current_quantity, receipt_date, expiration_date, qc_status, status, date_opened ) SELECT nextval('clinlims.inventory_lot_seq'), uuid_generate_v4(), ii.id, 'IMMUNO-CD4-2025-004', 100.0, 65.0, CURRENT_TIMESTAMP - INTERVAL '45 days', CURRENT_TIMESTAMP + INTERVAL '8 months', 'PASSED', 'IN_USE', CURRENT_TIMESTAMP - INTERVAL '20 days' FROM clinlims.inventory_item ii WHERE ii.name = 'CD4+ Cell Count Kit' AND ii.project_name = 'Immunology Laboratory' AND NOT EXISTS ( SELECT 1 FROM clinlims.inventory_lot il2 WHERE il2.lot_number = 'IMMUNO-CD4-2025-004' );
-- Universal Tubes Lot (No project) INSERT INTO clinlims.inventory_lot ( id, fhir_uuid, inventory_item_id, lot_number, initial_quantity, current_quantity, receipt_date, expiration_date, qc_status, status ) SELECT nextval('clinlims.inventory_lot_seq'), uuid_generate_v4(), ii.id, 'GENERAL-TUBES-2025-005', 1000.0, 850.0, CURRENT_TIMESTAMP - INTERVAL '60 days', CURRENT_TIMESTAMP + INTERVAL '24 months', 'PASSED', 'ACTIVE' FROM clinlims.inventory_item ii WHERE ii.name = 'Universal Sample Tubes' AND (ii.project_name IS NULL OR ii.project_name = '') AND NOT EXISTS ( SELECT 1 FROM clinlims.inventory_lot il2 WHERE il2.lot_number = 'GENERAL-TUBES-2025-005' );

-- Update Immunology Lab lots with opening dates and storage locations UPDATE clinlims.inventory_lot SET date_opened = CURRENT_TIMESTAMP - INTERVAL '10 days', storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'Immunology Ref A - Shelf 1' ) WHERE lot_number IN ('CLB-2024-005', 'PK-2024-006') AND date_opened IS NULL;
-- Update MNTD Lab lots with varying opening scenarios UPDATE clinlims.inventory_lot SET date_opened = CURRENT_TIMESTAMP - INTERVAL '5 days', storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'MNTD Ref - Shelf 1' ) WHERE lot_number IN ('EK-2024-001', 'PM-2024-003') AND date_opened IS NULL;
-- Update some lots with storage but NO opening date (unopened) UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'MNTD Ref - Shelf 1' ) WHERE lot_number IN ('RPB-2024-002', 'MRK-2024-004') AND storage_location_id IS NULL;
-- Update room temperature items UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'RT Cabinet - Shelf A' ) WHERE lot_number IN ('ETH-2024-007', 'NFW-2024-008') AND storage_location_id IS NULL;
-- Update equipment lots (no opening dates, stored in rooms) UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'Immunology Laboratory Room' ) WHERE lot_number IN ('CF-001', 'VM-003', 'BSC-005') AND storage_location_id IS NULL;
UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'MNTD Laboratory Room' ) WHERE lot_number IN ('TC-002', 'MP-004', 'ND-006') AND storage_location_id IS NULL;

-- Assign storage locations to new lots UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'MNTD Ref - Shelf 1' ) WHERE lot_number IN ('MNTD-RDT-2025-001', 'MNTD-DNG-2025-002') AND storage_location_id IS NULL;
UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'Immunology Ref A - Shelf 1' ) WHERE lot_number IN ('IMMUNO-HIV-2025-003', 'IMMUNO-CD4-2025-004') AND storage_location_id IS NULL;
UPDATE clinlims.inventory_lot SET storage_location_id = ( SELECT id FROM clinlims.inventory_storage_location WHERE name = 'RT Cabinet - Shelf A' ) WHERE lot_number = 'GENERAL-TUBES-2025-005' AND storage_location_id IS NULL;

SELECT setval('clinlims.inventory_item_seq', (SELECT COALESCE(MAX(id), 0) FROM clinlims.inventory_item), true);
SELECT setval('clinlims.inventory_lot_seq', (SELECT COALESCE(MAX(id), 0) FROM clinlims.inventory_lot), true);
SELECT setval('clinlims.inventory_storage_location_seq', (SELECT COALESCE(MAX(id), 0) FROM clinlims.inventory_storage_location), true);
